using UnityEngine; using UnityEngine.InputSystem;  public class Rock: MonoBehaviour {     public int health;      // Start is called once before the first execution of Update after the MonoBehaviour is created     void Start()     {              }      // Update is called once per frame     void Update()     {         if (health == 0)         {             Destroy(gameObject);         }     }     public void TakeDamage(int damage)     {         health -= damage;     }      public void SpawnClick()     {         Vector3 spawnPos = new Vector3(6.07f, 0f, 0f);         if (Mouse.current.leftButton.wasPressedThisFrame == true)         {             GameObject PlsSapwn = Instantiate(gameObject, spawnPos, Quaternion.identity);             health = 30;         }     } }